using namespace std;

class Solution {
public:
    string gcdOfStrings(string str1, string str2) {
        int len1 = str1.size();
        int len2 = str2.size();

        int g = gcd(len1, len2);

        for (int d = g; d >= 1; --d) {
            if (g % d != 0) continue;

            string x = str1.substr(0, d);
            bool valid = true;

            // Check for str1
            int m = x.size();
            if (len1 % m != 0) {
                valid = false;
            } else {
                for (int i = 0; i < len1; i += m) {
                    if (str1.substr(i, m) != x) {
                        valid = false;
                        break;
                    }
                }
            }

            if (!valid) continue;

            // Check for str2
            if (len2 % m != 0) {
                valid = false;
            } else {
                for (int i = 0; i < len2; i += m) {
                    if (str2.substr(i, m) != x) {
                        valid = false;
                        break;
                    }
                }
            }

            if (valid) {
                return x;
            }
        }

        return "";
    }
};

